    """Merge multiple sorted lists."""
    import heapq
    heap = []
    result = []
    iterators = [iter(lst) for lst in lists]
    for i, it in enumerate(iterators):
        try:
            val = next(it)
            heapq.heappush(heap, (val, i))
        except StopIteration:
            pass
    while heap:
