def {{nama_fungsi}}(a, b):
    """Return panjang LCS."""
    m, n = len(a), len(b)
    dp = [[0]*(n+1) for _ in range(m+1)]
    for i in range(1, m+1):
        for j in range(1, n+1):
            if a[i-1] == b[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])
    return dp[m][n]

def {{nama_fungsi}}(graph):
    """graph: dict node -> list neighbors. Return topo order list."""
    from collections import deque, defaultdict
    indeg = defaultdict(int)
    nodes = set(graph.keys())
    for u in graph:
        for v in graph[u]:
            indeg[v] += 1
            nodes.add(v)
    q = deque([n for n in nodes if indeg[n] == 0])
    order = []
    while q:
        u = q.popleft()
        order.append(u)
        for v in graph.get(u, []):
            indeg[v] -= 1
            if indeg[v] == 0:
                q.append(v)
    if len(order) != len(nodes):
        raise ValueError("Graph contains cycle")
    return order

