def {{nama_fungsi}}(root, interval=1.0, duration=10):
    """Yield (event, path) selama duration detik. Polling sederhana."""
    import os, time
    def snapshot():
        snap = {}
        for dirpath, _, filenames in os.walk(root):
            for name in filenames:
                p = os.path.join(dirpath, name)
                try:
                    snap[p] = os.path.getmtime(p)
                except OSError:
                    pass
        return snap
    prev = snapshot()
    end = time.time() + duration
    while time.time() < end:
        time.sleep(interval)
        cur = snapshot()
        for p in cur:
            if p not in prev:
                yield ('created', p)
            elif cur[p] != prev[p]:
                yield ('modified', p)
        for p in prev:
            if p not in cur:
                yield ('deleted', p)
        prev = cur

