    """Decorator: graceful shutdown on signals."""
    import signal, functools
    if signals is None:
        signals = [signal.SIGINT, signal.SIGTERM]
    def decorator(f):
        @functools.wraps(f)
        def wrapper(*args, **kwargs):
            stop = {'flag': False}
            def handler(signum, frame):
                stop['flag'] = True
            old = {}
            for s in signals:
                try:
                    old[s] = signal.signal(s, handler)
                except Exception:
                    pass
            try:
                return f(*args, stop_flag=lambda: stop['flag'], **kwargs)
            finally:
                for s, h in old.items():
                    try:
                        signal.signal(s, h)
                    except Exception:
                        pass
        return wrapper
    if func is None:
        return decorator
    return decorator(func)

