    """Vector store in-memory dengan nearest-neighbor search berbasis cosine similarity."""

    def __init__(self):
        self._store = []  # list of {"text": str, "vector": list[float], "metadata": dict}

    def add(self, text, vector, metadata=None):
        """Tambahkan satu dokumen beserta vektornya ke store."""
        self._store.append({
            "text": text,
            "vector": vector,
            "metadata": metadata or {},
        })

    def search(self, query_vector, top_k={{top_k_default}}):
        """Cari top_k dokumen paling mirip dengan query_vector.
        Kembalikan list of dict {text, score, metadata} diurutkan dari paling mirip.
        """
        scored = []
        for entry in self._store:
            score = self._cosine(query_vector, entry["vector"])
            scored.append({"text": entry["text"], "score": score, "metadata": entry["metadata"]})
        scored.sort(key=lambda x: x["score"], reverse=True)
        return scored[:top_k]

    def __len__(self):
        return len(self._store)

    @staticmethod
    def _cosine(a, b):
        dot = sum(x * y for x, y in zip(a, b))
        norm_a = math.sqrt(sum(x * x for x in a))
        norm_b = math.sqrt(sum(y * y for y in b))
        if norm_a == 0.0 or norm_b == 0.0:
            return 0.0
        return dot / (norm_a * norm_b)

