class {{nama_kelas}}:
    """Circuit breaker: blokir panggilan sementara setelah {{failure_threshold}} kegagalan berturut-turut.
    Coba pulih setelah {{recovery_timeout}} detik.
    """

    CLOSED = "closed"      # Normal, panggilan diizinkan
    OPEN = "open"          # Gagal terlalu banyak, panggilan diblokir
    HALF_OPEN = "half_open"  # Sedang uji coba pemulihan

    def __init__(self):
        self.state = self.CLOSED
        self._failure_count = 0
        self._last_failure_time = None

    def call(self, func, *args, **kwargs):
        """Jalankan func melalui circuit breaker. Lempar RuntimeError jika circuit terbuka."""
        if self.state == self.OPEN:
            elapsed = time.time() - self._last_failure_time
            if elapsed >= {{recovery_timeout}}:
                self.state = self.HALF_OPEN
            else:
                raise RuntimeError(
                    f"Circuit terbuka. Coba lagi dalam "
                    f"{{{recovery_timeout}} - elapsed:.0f} detik."
                )
        try:
            result = func(*args, **kwargs)
            self._on_success()
            return result
        except Exception as exc:
            self._on_failure()
            raise exc

    def _on_success(self):
        self._failure_count = 0
        self.state = self.CLOSED

    def _on_failure(self):
        self._failure_count += 1
        self._last_failure_time = time.time()
        if self._failure_count >= {{failure_threshold}}:
            self.state = self.OPEN

